1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Simplest cases — quote with edge inputs
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // Base premiums for main items
15	  it("single plain sword (newcomer, first contract) → 100 + 10 first-insurance + 5 fee = 115 G", () => {
16	    const result = runScenario({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }] }],
19	    });
20	    expect(result).toEqual({ results: [{ premium: 115 }] });
21	  });
22	  it("single plain amulet (newcomer, first contract) → 60 + 6 first-insurance + 5 fee = 71 G (rounded up)", () => {
23	    const result = runScenario({
24	      customer: { yearsWithMHPCO: 0 },
25	      steps: [{ op: "quote", items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }] }],
26	    });
27	    expect(result).toEqual({ results: [{ premium: 71 }] });
28	  });
29	  it.todo("single plain staff (newcomer, first contract) → 80 + 8 first-insurance + 5 fee = 93 G");
30	  it.todo("single plain potion (newcomer, first contract) → 40 + 4 first-insurance + 5 fee = 49 G");
31	
32	  // Components — building-block discount
33	  it.todo("2 runes → base premium 50 G (no block)");
34	  it.todo("3 runes → base premium 60 G (block applies)");
35	  it.todo("4 runes → base premium 100 G (no block; block requires exactly 3)");
36	  it.todo("7 runes → base premium 175 G (no block; 7 = no group of exactly 3 with leftovers)");
37	
38	  // 'Alike' components — same type, not family
39	  it.todo("2 runes + 1 moonstone → base premium 75 G (no block, different types)");
40	  it.todo("3 runes + 3 moonstones → base premium 120 G (two separate blocks)");
41	
42	  // Modifier scope on multi-item policies
43	  it.todo("cursed sword + plain amulet → 100 + 60 + 50 (curse on sword only) = 210 G before further modifiers and fee");
44	
45	  // Modifier thresholds
46	  it.todo("customer with exactly 2 years → loyalty discount applies");
47	  it.todo("sword enchantment exactly 5 → high-enchantment surcharge applies");
48	  it.todo("cursed sword enchantment exactly 5 → both curse and high-enchantment surcharges apply");
49	  it.todo("sword enchantment 4, not cursed → no surcharge");
50	
51	  // Rounding in MHPCO's favor
52	  it.todo("premium 197.5 G → rounded up to 198 G");
53	
54	  // Integration examples
55	  it.todo("newcomer with cursed sword (steel, ench 3) → 165 G");
56	  it.todo("long-standing customer (3 years), 2nd contract, cursed sword ench 7 → 160 G");
57	
58	  // Quote errors
59	  it.todo("quote with unknown item type → CLI exits non-zero, writes error to stderr, no results");
60	
61	  // Claim — standard reimbursement
62	  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (500 − 100 deductible)");
63	  it.todo("damage to a rune (no enchantment/material), damage 200 G → payout 100 G (200 − 100)");
64	
65	  // Claim — enchantment threshold and dragon material
66	  it.todo("dragon sword, ench 8, damage 1000 G → payout 400 G (50% rule, then deductible)");
67	  it.todo("dragon sword, ench 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
68	  it.todo("dragon sword, ench 5, damage 800 G → payout 700 G (dragon full, then deductible)");
69	  it.todo("steel sword, ench 9, damage 1000 G → payout 400 G (50% rule, then deductible)");
70	
71	  // Multiple items + deductible per damage event
72	  it.todo("dragon attack on insured sword (500 G) + amulet (300 G) → payout 600 G (deductible per damaged item)");
73	
74	  // Multiple items of the same type
75	  it.todo("policy covers two swords → insurance sum 2000, cap 4000; both damaged → each its own deductible");
76	  it.todo("damages contains more entries of a type than policy covers → CLI exits non-zero");
77	
78	  // Cap rules
79	  it.todo("policy with sword + amulet → insurance sum 1600, cap 3200");
80	  it.todo("policy with cursed sword (premium 165) → cap 2000 (based on unmodified insurance value)");
81	  it.todo("policy with sword + 3 runes (block) → insurance sum 1750 (block discount doesn't affect insurance sum)");
82	  it.todo("sword cap 2000; two successive claims of 1500 → 1st payout 1400 (cap rem 600), 2nd payout 600 (cap rem 0)");
83	
84	  // Rounding payout
85	  it.todo("payout 350.5 G → rounded down to 350 G (MHPCO's favor)");
86	
87	  // Claim errors
88	  it.todo("claim references damage entry whose item is not part of the policy → CLI exits non-zero with stderr");
89	  it.todo("claim damage with negative amount → CLI exits non-zero with stderr");
90	});
