1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	};
8	
9	type Item = { type: string };
10	type Step = { op: "quote"; items: Item[] };
11	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
12	
13	const quotePremium = (items: Item[]): number => {
14	  if (items.length === 0) return PROCESSING_FEE;
15	  const policyBase = items.reduce((sum, it) => sum + BASE_PREMIUM[it.type], 0);
16	  const firstInsurance = items.reduce((sum, it) => sum + BASE_PREMIUM[it.type] * FIRST_INSURANCE_RATE, 0);
17	  return Math.ceil(policyBase + firstInsurance + PROCESSING_FEE);
18	};
19	
20	export const runScenario = (input: unknown): unknown => {
21	  const scenario = input as Scenario;
22	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
23	  return { results };
24	};
